-- CATALOG upsert
on conflict (ean) do update set
 brand=excluded.brand,name=excluded.name,category=excluded.category,image_url=excluded.image_url,
 source_url=excluded.source_url,score=excluded.score,score_label=excluded.score_label,score_tone=excluded.score_tone,
 count_total=excluded.count_total,ingredients_text=excluded.ingredients_text,is_active=excluded.is_active,
 count_orange=excluded.count_orange,count_rouge=excluded.count_rouge,search_norm=excluded.search_norm,search_key=excluded.search_key;

-- CLASSIFICATIONS upsert
on conflict (ean) do update set
 category=excluded.category,subcategory=excluded.subcategory,subsubcategory=excluded.subsubcategory,
 category_slug=excluded.category_slug,method=excluded.method,confidence=excluded.confidence,
 gpt_verified=excluded.gpt_verified,score=excluded.score,count_total=excluded.count_total,updated_at=now();
